    created: async function () {
        
        var vm = this;
        const url = window.location.pathname; 
        if (url.includes('/ManagePlan/')) {
            vm.planId = parseInt(this.$route.params.id);
        }
        if (this.serviceRuleItem && this.serviceRuleItem.ruleCondition) {
            this.form.selectedFlag = this.serviceRuleItem.ruleCondition.selectedFlag ? this.serviceRuleItem.ruleCondition.selectedFlag : { value: 'N', color: 'grey' };
