                setTimeout(async function () {
                    vm.isEditMode = true;
                   await vm.BindRuleConditions(vm.conditionId);
                }, 200);
            }
            else if(vm.reqFrom === "ViewBillingConditionForService" ){
                setTimeout(async function () {
                    vm.isEditMode = true;
                    await vm.BindRuleConditions(vm.conditionId);
                }, 200);
            }
        }
        else if (vm.reqFrom === "fromBillingService") {
            vm.isEditMode = false;
            await vm.BindRuleConditions(vm.conditionId);
            if(this.category.toLowerCase() == 'global'){
                vm.isShowServiceDetail = true;
            }
            else{
                vm.isShowServiceDetail = false;
            }
           
        }
        else if (vm.reqFrom === "addBillingService") {
            vm.isEditMode = false;
            vm.isShowServiceDetail = false;
        }
        vm.toggleGroup();
        debugger;
        if (vm.reqFrom !== "fromBillingService" && vm.reqFrom !== "addBillingService") {
            await vm.GetAddonMapByServiceId();
        }
        vm.syncConditionBlocks();
