        handleFieldChange: function (row) {
            const allOptions = Object.values(this.groupedOptions).flat();
            const selectedOption = allOptions.find(opt => opt.value === row.field);
            if (!selectedOption) return;

            this.$set(row, 'isIntervalOperator', false);
            this.$set(row, 'operator', '');
            this.$set(row, 'value', '');
            this.$set(row, 'valueTo', '');
            this.$set(row, 'operatorList', []);

            this.$set(row, 'sqlType', selectedOption.sqlType);

            if (selectedOption.sqlType === 'datetime') {
                this.$set(row, 'datetimeMode', row.datetimeMode || 'date');
            } else {
                this.$delete(row, 'datetimeMode');
            }

            const url = "templateId=" + selectedOption.value;
            DataService.GetOperators(url).then((response) => {
                const json = response.data;
                if (json != null) {
                    this.$set(row, 'operatorList', json);
                }
            });
        },
        isIntervalOperator(operatorId, operatorList) {
            if (!operatorId || !operatorList?.length) return false;

            const operator = operatorList.find(
                op => op.OPERATOR_ID === operatorId
            );

            if (!operator) return false;

            const expr = operator.OPERATOR_EXPRESSION?.toUpperCase() || '';

            return expr.includes('DIFF');
        },
        handleOperatorChange: function (row) {
            var vm = this;
            this.$set(row, 'isIntervalOperator', false);
            const allOptions = Object.values(this.groupedOptions).flat();
            const selectedOption = allOptions.find(opt => opt.value === row.field);
            if (!selectedOption) return;
            const isInterval = this.isIntervalOperator(row.operator, row.operatorList); 
            this.$set(row, 'isIntervalOperator', isInterval);
            this.$set(row, 'sqlType', selectedOption.sqlType);
            this.$set(row, 'valueOptions', []);
            this.$set(row, 'value', '');
            this.$set(row, 'valueTo', '');

            if (selectedOption.sqlType == 'select' && (selectedOption.picklistOptions).toLowerCase() != "lookup") {
                if (selectedOption.picklistOptions && selectedOption.picklistOptions.trim() !== '') {
                    const dropValue = selectedOption.picklistOptions.split(',').map(option => ({
                        first_value: null,
                        name: option.trim(),
                        value: option.trim().replace(/\s+/g, '-'),
                        second_value: null
                    }));
                    this.$set(row, 'valueOptions', dropValue);
                }
            } else if (selectedOption.sqlType == 'select' && (selectedOption.picklistOptions).toLowerCase() == "lookup") {
                var params = `id=&moduleName=&type=${selectedOption.fieldCode}&search=`;
                DataService.GetDDLData(params).then((response) => {
                    if (response.data) {
                        var json = response.data;
                        if (json != null) {
                            this.$set(row, 'valueOptions', response.data.DATA);
                        }
                    }
                });
            } else if (selectedOption.sqlType == 'bool') {
                var radioValue = vm.MakeArray(selectedOption.picklistOptions, 'radio');
                if (radioValue.length > 0) {
                    this.$set(row, 'valueOptions', radioValue);
                }
            }
        },
        isLeafTogglePopup() {
            this.form.showPopup = !this.form.showPopup;
        },
        isLeafSelectFlag(flag) {
            this.form.selectedFlag = flag;
            this.form.showPopup = false;
        },
        isAdderTogglePopup(adder) {
            adder.showPopup = !adder.showPopup;
        },
        isAdderSelectFlag(adder, flag) {
            adder.selectedFlag = flag;
            adder.showPopup = false;
        },
        onDatetimeModeChange(row, mode) {
            // Explicitly set mode and clear values so old date/time values don't conflict
            row.datetimeMode = mode;
            row.value = '';
            row.valueTo = '';
        },
        toggleGroup(groupName) {
            const group = groupName || 'Client';
            this.$set(this.expandedGroups, group, !this.expandedGroups[group]);
        },
        GetBillingRuleFieldList: async function () {
            var vm = this;
            await DataService.GetBillingRuleFieldList().then(response => {
                if (response.data.status == 'Success') {
                    if (response.data.result.AVAILABLE_FIELDS != null) {
                        const availableFields = response.data.result.AVAILABLE_FIELDS?.[0] || [];
                        const groupedOptions = {};

                        availableFields.forEach(moduleData => {
                            const moduleName = moduleData.SubModule;
                            if (Array.isArray(moduleData?.CustomFields) && moduleData.CustomFields.length > 0) {
                                groupedOptions[moduleName] = moduleData.CustomFields.map(item => ({
                                    value: item?.CustomFieldId || '',
                                    columnName: item?.FieldName || '',
                                    label: item?.DisplayName || '',
                                    tableName: item?.TableName || '',
                                    sqlType: item?.dttype?.[0]?.DataTypeCode || '',
                                    picklistOptions: item?.picklist_options || '',
                                    dtCode: item?.dt_code || '',
                                    dropdownType: item?.dropdown_type || '',
                                    fieldCode: item?.field_code || '',
                                    joinFieldName: item?.JoinFieldName || ''

                                }));
                            }
                        });
                        // Only assign if there is at least one valid module with data
                        if (Object.keys(groupedOptions).length > 0) {
                            this.groupedOptions = groupedOptions;
                        }
                    }
                }
            })
        },
        GetFieldsListBySetupId: async function () {
            var vm = this;
            var url = `setupId=${vm.setupId}&isShowUnit=${vm.isShowUnit}&isGroupBy=${vm.isGroupBy}&isComboChargeScope=${vm.isComboChargeScope}`;
            await DataService.GetFieldsListBySetupId(url).then((response) => {
                if (response.data && response.data.length > 0) {
                    const availableFields = JSON.parse(response.data);
                    const flatOptions = [];
                    availableFields.forEach(item => {
                        flatOptions.push({
                            value: item?.TEMPLATE_ID ?? null,
                            columnName: item?.COLUMN_NAME ?? null,
                            label: item?.DISPLAY_NAME ?? null,
                            tableName: item?.TABLE_NAME ?? null,
                            sqlType: item?.DATA_TYPE ?? null,
                            picklistOptions: null,
                            dtCode: null,
                            dropdownType: null,
                            fieldCode: null,
                            joinFieldName: item?.COLUMN_NAME ?? null
                        });
                    });

                    // Assign only if data exists
                    if (flatOptions.length > 0) {
                        this.groupedOptions = flatOptions;
                    }                    
                }
            });
        },
