        onToValueChange(val, index) {
            const adder = this.visibleAdderRows[index];
            if (!adder) return;

            if (val === '∞') {
                adder.to = '∞';
            } else if (val.trim() === '') {
                adder.to = '';
            } else {
                const num = Number(val);
                adder.to = isNaN(num) ? '' : num;
            }
        },
