        formatDate(dateObj) {
            if (!dateObj) return null;
            const d = new Date(dateObj);
            const year = d.getFullYear();
            const month = d.getMonth() + 1;
            const day = d.getDate();
            return `${month}/${day}/${year}`;
        },
        formatDatePickerDisplay(inputValue) {
            // Format the date picker's inputValue to M/D/YYYY for display (no leading zeros)
            if (!inputValue) return '';

            var date;
            var inputStr = String(inputValue).trim();

            // Handle Date object directly
            if (inputValue instanceof Date) {
                date = inputValue;
            } else if (typeof inputValue === 'string') {
                // Check if it's already in a date format
                var parts = inputStr.split(/[-\/]/);
                if (parts.length === 3 && parts[0].length === 2 && parts[1].length === 2 && parts[2].length === 4) {
                    var firstPart = parseInt(parts[0], 10);
                    var secondPart = parseInt(parts[1], 10);

                    // If first part > 12, it's likely DD/MM/YYYY format
                    if (firstPart > 12 && secondPart <= 12) {
                        // Parse as DD/MM/YYYY
                        date = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
                    } else if (firstPart <= 12 && secondPart <= 12) {
                        // Could be either format, but if first part <= 12, assume MM/DD/YYYY
                        if (secondPart > 12) {
                            // Definitely MM/DD/YYYY
                            date = new Date(parseInt(parts[2]), parseInt(parts[0]) - 1, parseInt(parts[1]));
                        } else {
                            // Ambiguous - try MM/DD/YYYY first (most common)
                            date = new Date(parseInt(parts[2]), parseInt(parts[0]) - 1, parseInt(parts[1]));
                            // Validate the date
                            if (date.getMonth() + 1 !== parseInt(parts[0]) || date.getDate() !== parseInt(parts[1])) {
                                // Try DD/MM/YYYY
                                date = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
                            }
                        }
                    } else {
                        // Try MM/DD/YYYY first
                        date = new Date(parseInt(parts[2]), parseInt(parts[0]) - 1, parseInt(parts[1]));
                        if (isNaN(date.getTime()) || date.getMonth() + 1 !== parseInt(parts[0])) {
                            // Try DD/MM/YYYY
                            date = new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
                        }
                    }
                } else if (parts.length === 3 && parts[0].length === 4) {
                    // YYYY-MM-DD or YYYY/MM/DD format
                    date = new Date(parseInt(parts[0]), parseInt(parts[1]) - 1, parseInt(parts[2]));
                } else {
                    // Try standard Date parsing
                    date = new Date(inputValue);
                }
            } else {
                date = new Date(inputValue);
            }

            // Validate the date
            if (isNaN(date.getTime())) {
                return inputStr; // Return original if can't parse
            }

            // Format as M/D/YYYY (no leading zeros)
            var month = date.getMonth() + 1;
            var day = date.getDate();
            var year = date.getFullYear();
            return month + '/' + day + '/' + year;
        },
        inferDatetimeModeFromValues(val1, val2) {
            // Detect if provided values look like time-only strings; otherwise default to date
            const check = (v) => {
                if (!v) return null;
                const s = String(v).trim();
                // Common time-only patterns
                const timePatterns = [
                    /^(\d{1,2}):(\d{2})(\s*(AM|PM))?$/i,           // HH:mm or HH:mm AM/PM
                    /^(\d{1,2}):(\d{2}):(\d{2})(\s*(AM|PM))?$/i,   // HH:mm:ss or HH:mm:ss AM/PM
                    /^(\d{1,2}):(\d{2}):(\d{2})\.\d+$/i            // HH:mm:ss.milliseconds
                ];
                if (timePatterns.some(p => p.test(s))) return 'time';
                return null;
            };
            return check(val1) || check(val2) || 'date';
        },
        databaseConditionText() {
            // Helper function to generate SQL for a single condition
            const generateConditionSQL = (row) => {
                const field = this.fieldSqlConditionMap[row.field] || row.field || '';

                let operator = '';
                let operatorDisplay = '';
                if (row.operatorList && Array.isArray(row.operatorList)) {
                    const op = row.operatorList.find(o => o.OPERATOR_ID === row.operator);
                    operator = op ? (op.OPERATOR_SQL_NAME || op.OPERATOR_EXPRESSION) : row.operator;
                    operatorDisplay = op ? (op.OPERATOR_DISPLAY_NAME || '') : '';
                } else {
                    operator = row.operator;
                    operatorDisplay = row.operatorDisplay || '';
                }

                operator = (operator || '').toLowerCase();
                const displayCheck = (operatorDisplay || '').trim().toLowerCase();

                // ✅ handle "equal to / not equal to one of multiple possible values"
                if (
                    displayCheck === 'not equal to one of multiple possible values' ||
                    displayCheck === 'equal to one of multiple possible values'
                ) {
                    const values = Array.isArray(row.value) ? row.value : [row.value];
                    const selectedValues = values.map(v => {
                        const val = typeof v === "object" && v !== null ? v.value : v;
                        const match = row.valueOptions?.find(opt => opt.value === val);
                        const finalVal = match ? match.value : val;
                        return isNaN(finalVal) ? `'${finalVal}'` : finalVal;
                    });
                    const value = selectedValues.join(', ');
                    return `(${field} ${operator.toUpperCase()} (${value}))`;
                }

                // special cases
                if (operator === 'is week end' || operator === 'is working day') {
                    const days = (row.daysOfWeek || '').split(',').filter(Boolean).join(',');
                    return `(DATEPART(DW, ${field}) IN (${days}))`;
                }
                if (operator === 'is lowest') {
                    return `(${field} IS LOWEST)`;
                }
                if (operator === 'is highest') {
                    return `(${field} IS HIGHEST)`;
                }
                if (operator === 'is not lowest') {
                    return `(${field} IS NOT LOWEST)`;
                }
                if (operator === 'is not highest') {
                    return `(${field} IS NOT HIGHEST)`;
                }

                // DateDiff operators
                if (['minutesdiff','hoursdiff','daydiff','monthdiff','yeardiff'].includes(operator)) {
                    const unitMap = {
                        minutesdiff: 'minute',
                        hoursdiff: 'hour',
                        daydiff: 'day',
                        monthdiff: 'month',
                        yeardiff: 'year'
                    };
                    const diffUnit = unitMap[operator];
                    const compareField = this.fieldSqlConditionMap[row.additionalField] || row.additionalField;
                    const opSql = row.additionalOperator || '=';
                    return `(DATEDIFF(${diffUnit}, ${field}, ${compareField}) ${opSql} ${row.value})`;
                }

                // HAS WITH operator
                if (operator === 'has with') {
                    const withField = this.fieldSqlConditionMap[row.hasWithField] || row.hasWithField;
                    const withOp = row.hasWithOperator || '=';
                    return `(${field} HAS WITH ${withField} ${withOp} '${row.value}')`;
                }

                // BETWEEN / DATERANGE special case
                if ((operator === 'between' || operator === 'daterange') && row.valueTo) {
                    if (row.sqlType === 'time' || (row.sqlType === 'datetime' && row.datetimeMode === 'time')) {
                        const fromVal = row.value ? `'${row.value}'` : "''";
                        const toVal = row.valueTo ? `'${row.valueTo}'` : "''";
                        return `((CONVERT(time, ${field}) >= ${fromVal} AND CONVERT(time, ${field}) <= ${toVal}))`;
                    } else if (row.sqlType === 'date' || (row.sqlType === 'datetime' && row.datetimeMode === 'date')) {
                        const dateVal = row.value instanceof Date ? row.value : new Date(row.value);
                        const dateValTo = row.valueTo instanceof Date ? row.valueTo : new Date(row.valueTo);
                        const fromDate = this.formatDate(dateVal);
                        const toDate = this.formatDate(dateValTo);
                        return `(${field} BETWEEN '${fromDate}' AND '${toDate}')`;
                    } else {
                        return `(${field} BETWEEN ${row.value} AND ${row.valueTo})`;
                    }
                }

                let value = '';
                if (row.sqlType === 'nvarchar' || row.sqlType === 'string') {
                    if (operator.includes('starts with')) {
                        operator = 'LIKE';
                        value = `'${row.value}%'`;
                    } else if (operator.includes('ends with')) {
                        operator = 'LIKE';
                        value = `'%${row.value}'`;
                    } else if (operator.includes('like')) {
                        operator = 'LIKE';
                        value = `'%${row.value}%'`;
                    } else if (operator.includes('in')) {
                        operator = 'IN';
                        const arr = Array.isArray(row.value) ? row.value : (row.value || '').split(',');
                        value = `(${arr.map(v => `'${v.trim()}'`).join(',')})`;
                    } else {
                        value = `'${row.value}'`;
                    }
                } else if ((row.sqlType === 'date' || (row.sqlType === 'datetime' && row.datetimeMode === 'date')) && row.value) {
                    const dateVal = row.value instanceof Date ? row.value : new Date(row.value);
                    value = `'${this.formatDate(dateVal)}'`;
                } else if ((row.sqlType === 'time' || (row.sqlType === 'datetime' && row.datetimeMode === 'time')) && row.value) {
                    // For time-only comparisons (non-between), compare CONVERT(time, field) with the selected time string
                    value = `'${row.value}'`;
                    return `(CONVERT(time, ${field}) ${operator.toUpperCase()} ${value})`;
                } else if (row.sqlType === 'bool') {
                    value = row.value ? 1 : 0;
                } else if(displayCheck === 'equal to' && row.sqlType ==='select'){
                    if (typeof row.value === 'string') {
                        value = `'${row.value}'` || '';
                    }
                } else {
                    value = row.value ?? '';
                }
                return `(${field} ${operator.toUpperCase()} ${value})`;
            };

            // Process conditionBlocks instead of form.conditions for proper grouping
            return this.conditionBlocks.map((block, blockIndex) => {
                // Generate SQL for all conditions within this block
                const blockConditions = block.conditions
                    .filter(condition => condition.field && condition.operator)
                    .map((condition, conditionIndex) => {
                        const relation = conditionIndex > 0 ? ` ${block.operator || 'AND'} ` : '';
                        return `${relation}${generateConditionSQL(condition)}`;
                    })
                    .join('');

                if (!blockConditions) return '';

                // Wrap the entire block in parentheses if it has multiple conditions or if it's not the first block
                const shouldWrapBlock = block.conditions.filter(c => c.field && c.operator).length > 1 || blockIndex > 0;
                const blockSQL = shouldWrapBlock ? `(${blockConditions})` : blockConditions;

                // Add join operator with next block
                if (blockIndex === 0) return blockSQL;
                const joinOp = block.joinWithPrevious || 'OR';
                return ` ${joinOp} ${blockSQL}`;
            }).filter(block => block).join('');
        },
