        async saveAddRule() {
            var vm = this;
            this.syncFormConditions();
            if (!this.hasRuleConfirmation && this.reqFrom === "fromBillingService") {
                vm.$parent.isManageBillingRuleForm =false;
                return;
            }
            this.showError = true;
            if (!this.conditionName) {
                return;
            }
            if (vm.conditionId != 0) {
                this.form.conditionId = vm.conditionId;
            }
            const conditionData = this.conditionText;
            const sqlDatabasecondition = this.databaseConditionText();
            if (Array.isArray(this.form.conditions)) {
                this.form.conditions.forEach(condition => {
                    if (condition.sqlType === 'date' || (condition.sqlType === 'datetime' && condition.datetimeMode === 'date')) {
                        if (condition.value) {
                            condition.value = this.formatDate(condition.value);
                        }
                        if (condition.valueTo) {
                            condition.valueTo = this.formatDate(condition.valueTo);
                        }
                    }
                    if (condition?.operator && Array.isArray(condition.value) && condition.value.length > 0) {
                        const operatorId = condition.operator;
                        const matchedOperator = condition.operatorList.find(op => op.OPERATOR_ID === operatorId);
                        if (matchedOperator && (matchedOperator.OPERATOR_DISPLAY_NAME?.toLowerCase() === "equal to one of multiple possible values" || matchedOperator.OPERATOR_DISPLAY_NAME?.toLowerCase() === "not equal to one of multiple possible values")) {
                            condition.value = condition.value.map(v => v.value).join(',');
                        }
                    }
                });
            }
            this.form.serviceId = this.serviceId;
            const payload = JSON.parse(JSON.stringify(this.form));
            payload.adderRows.forEach(adder => {
                if (adder.to === '∞' || adder.to === Infinity) {
                    adder.to = null;
                }
            });
            if(payload.rateToggle == true){
                payload.isLeaf =true;
            }
            const obj = JSON.stringify(payload);
            var requestPayload = { objData: obj, ruleCondition: conditionData, conditionName: this.conditionName, configuration_id: vm.configurationId,sqlcondition:sqlDatabasecondition,categoryId :this.categoryId,setupId : this.setupId,isVisible:true,serviceDescription : this.serviceDescription};
            await DataService.SaveAddRule(requestPayload).then(response => {
                if (response.data != null) {
                    const label = vm.isBillingType ? vm.$t('Service') : vm.$t('BillingCondition');
                    if (response.data.Status == "Success" && response.data.Result == "1") {
                        vm.Close();
                        if (vm.viewType == 'serviceRuleCondition') {
                            vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('BillingRule')]), "Success", true, vm.$t('Alert'));
                            vm.$parent.getConditionRecords();
                        }
                        if (vm.reqFrom == "fromBillingService" || vm.reqFrom == "addBillingService") {
                            vm.ShowAlert(vm.$t('AddedSuccess', [label]), "Success", true, vm.$t('Alert'));
                            vm.$parent.FetchData();
                        }
                        vm.isLoading = false;
                        this.$emit('rule-saved', obj);
                    }
                    else if (response.data.Status == "Success" && response.data.Result == "3") {
                        vm.Close();
                        if (vm.reqFrom == "fromBillingService" || vm.reqFrom == "addBillingService") {
                            vm.ShowAlert(vm.$t('UpdatedSuccess', [label]), "Success", true, vm.$t('Alert'));
                            vm.$parent.FetchData();
                        }
                        else{
                            vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('BillingRule')]), "Success", true, vm.$t('Alert'));
                        }
                        vm.isLoading = false;
                        this.$emit('rule-saved', obj);
                    }
                    else if (response.data.Result == "2") {
                        if (vm.reqFrom == "fromBillingService" || vm.reqFrom == "addBillingService") {
                            this.ShowAlert(this.$t('AlreadyExists', [label]), "failure", true, this.$t('Alert'));
                        }
                        else{
                            this.ShowAlert(this.$t('AlreadyExists', [this.$t('BillingRule')]), "failure", true, this.$t('Alert'));
                        }
                        
                    }
                    else {
                        if (vm.reqFrom == "fromBillingService" || vm.reqFrom == "addBillingService") {
                            vm.ShowAlert(vm.$t("ErrorWhileSaving", [label]), "danger", true, vm.$t("Alert"));
                            vm.isLoading = false;
                        }
                        else{
                            vm.ShowAlert(vm.$t("ErrorWhileSaving", [vm.$t("BillingRule")]), "danger", true, vm.$t("Alert"));
                        vm.isLoading = false;
                        }
                        
                    }
                }
            });
        },
