        syncConditionBlocks() {
            if (!this.form.conditions || this.form.conditions.length === 0) {
                this.conditionBlocks = [];
                return;
            }

            const blocks = [];
            let currentBlock = null;
            let bracketDepth = 0;
            let lastTopLevelRelation = null;

            const startNewBlock = (joinWithPrevious = '') => {
                currentBlock = {
                    operator: '',
                    joinWithPrevious,
                    conditions: []
                };
                blocks.push(currentBlock);
            };

            this.form.conditions.forEach((condition, index) => {
                const opening = (condition.openingBracket || '').toString();
                const closing = (condition.closingBracket || '').toString();
                const relation = (condition.relation || '').toUpperCase();

                // Increase depth BEFORE processing condition
                if (opening.includes('(')) {
                    bracketDepth += opening.split('(').length - 1;
                }

                // FIRST condition → always start a block
                if (!currentBlock) {
                    startNewBlock('');
                    currentBlock.operator = relation || 'AND';
                    lastTopLevelRelation = relation || 'AND';
                }
                // Split block ONLY if:
                // - at top level
                // - operator changed
                else if (
                    bracketDepth === 0 &&
                    relation &&
                    relation !== lastTopLevelRelation
                ) {
                    startNewBlock(relation);
                    currentBlock.operator = relation;
                    lastTopLevelRelation = relation;
                }

                // Push condition into current block
                currentBlock.conditions.push({
                    field: condition.field || '',
                    operator: condition.operator || '',
                    value: condition.value,
                    valueTo: condition.valueTo,
                    daysOfWeek: condition.daysOfWeek || '',
                    operatorList: condition.operatorList || [],
                    valueOptions: condition.valueOptions || [],
                    sqlType: condition.sqlType || '',
                    datetimeMode:
                        condition.sqlType === 'datetime'
                            ? (condition.datetimeMode ||
                                this.inferDatetimeModeFromValues(
                                    condition.value,
                                    condition.valueTo
                                ))
                            : (condition.datetimeMode || 'date'),
                    openingBracket: condition.openingBracket || '',
                    closingBracket: condition.closingBracket || ''
                });

                // Decrease depth AFTER condition
                if (closing.includes(')')) {
                    bracketDepth -= closing.split(')').length - 1;
                }

                // Update last top-level relation ONLY when outside brackets
                if (bracketDepth === 0 && relation) {
                    lastTopLevelRelation = relation;
                }
            });

            this.conditionBlocks = blocks;
        },



